function processBatch(csvFiles) {
  const goodRows = [];
  const badRows = [];

  csvFiles.forEach(file => {
    const rows = parseCSV(file);
    rows.forEach(row => {
      if (validate(row)) {
        goodRows.push(row);
      } else {
        badRows.push({...row, error: 'Validation failed', timestamp: new Date()});
