  // Write bad data
  writeToPath(badRows, 'bad_data/');

  // Upsert good data
  executeMerge(goodRows, 'target_table', ['region', 'order_id']);
}

function redactForRole(data, userRole) {
  if (userRole !== 'admin') {
    return data.map(row => ({...row, total_amount: 'REDACTED'}));
  }
  return data;
}
