## Code Example

```python
from datetime import datetime
from dateutil import tz

def to_utc(event_ts: str, region_tz: str) -> datetime:
    local = datetime.fromisoformat(event_ts.replace('Z', '+00:00'))
    timezone = tz.gettz(region_tz)
    if timezone is None:
        raise ValueError(f"Invalid timezone: {region_tz}")
    local = local.replace(tzinfo=timezone)
    return local.astimezone(tz.UTC)

def validate_record(record: dict) -> tuple[bool, str]:
    if not record.get('device_id'):
        return False, "device_id is null or missing"

    try:
        ts = to_utc(record['event_ts'], record['region'])
        if ts.year < 2000 or ts.year > 2100:
            return False, "event_ts out of reasonable range"
    except (ValueError, KeyError) as e:
        return False, f"invalid event_ts or region: {e}"

    valid_regions = {'US', 'EU', 'APAC'}
    if record.get('region') not in valid_regions:
        return False, f"invalid region: {record.get('region')}"

    return True, ""

CANONICAL_EVENT_TYPE_MAP = {
    'page_view': 'PAGE_VIEW',
    'click': 'CLICK',
    'purchase': 'PURCHASE',
    'signup': 'SIGN_UP'
}

def map_event_type(event_type: str) -> str:
    return CANONICAL_EVENT_TYPE_MAP.get(event_type, 'UNKNOWN')

def process_batch(input_df, bad_data_writer):
    valid_records = []
    bad_records = []

    for record in input_df.collect():
        is_valid, error_msg = validate_record.asDict(record)
        if is_valid:
            record['event_ts'] = to_utc(record['event_ts'], record['region'])
            record['event_type'] = map_event_type(record['event_type'])
            valid_records.append(record)
        else:
            record['error_reason'] = error_msg
            bad_records.append(record)

    bad_data_writer.write(bad_data_writer, bad_records)
    return valid_records
```

